+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Sales.History;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Mgt. (ID 30366).
+/// Handles clearing of Shopify fields when copying documents.
+/// </summary>
+codeunit 30366 "Shpfy Copy Document Mgt."
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", OnCopySalesDocOnAfterTransferPostedInvoiceFields, '', false, false)]
+    local procedure ClearShopifyFieldsOnAfterCopyFromPostedInvoice(var ToSalesHeader: Record "Sales Header"; SalesInvoiceHeader: Record "Sales Invoice Header"; OldSalesHeader: Record "Sales Header")
+    begin
+        ClearShopifyOrderIdFields(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", OnAfterCopySalesHeader, '', false, false)]
+    local procedure ClearShopifyFieldsOnAfterCopySalesHeader(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesHeader: Record "Sales Header"; FromDocType: Enum "Sales Document Type From")
+    begin
+        ClearShopifyOrderIdFields(ToSalesHeader);
+    end;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", OnAfterCopyPostedShipment, '', false, false)]
+    local procedure ClearShopifyFieldsOnAfterCopyFromPostedShipment(var ToSalesHeader: Record "Sales Header"; OldSalesHeader: Record "Sales Header"; FromSalesShipmentHeader: Record "Sales Shipment Header")
+    begin
+        ClearShopifyOrderIdFields(ToSalesHeader);
+    end;
+
+    local procedure ClearShopifyOrderIdFields(var SalesHeader: Record "Sales Header")
+    begin
+        SalesHeader."Shpfy Order Id" := 0;
+        SalesHeader."Shpfy Order No." := '';
+        SalesHeader."Shpfy Refund Id" := 0;
+    end;
+}

